css:
/** Ensure proper background color on panels for mobile view **/
.dualbox-main-container {
	background-color:#353535 !important;
}

/** All panels will be dark and transparent with rounded corners **/ 
.dualbox-panel {
  background-color:rgba(0,0,0,0.75); 
  color:#eee;
  border: 0px;
  border-radius:2px !important;
}

/** Reduce top left panel size **/
.dualbox-panel-top-left {
  width:224px;
}

.dualbox-panel-top-right {
  width:324px;
}

.dualbox-panel-bottom-right {
  width:128px;
  padding:0;
  background-color:rgba(0,0,0,0);
}


/** Following 2 blocks customize the loader (spinner) colors **/ 
.dualbox-bootstrap-loader {
  background-color:rgba(0,0,0,0);
}

.dualbox-load-label {
    color:rgba(255,193,7,1) !important;
}

/** reduce the margin between the images in radio-images **/
.dualbox-radio-imgcontainer {
  margin:0px;
}

/** reduce the margin between the 2 menu in radio-images **/
.dualbox-radio-container {
  margin-bottom:40px !important;
}

/** Change the color and shape of the line around selected image **/
.dualbox-radio-div [type=radio]:checked + img {
    /** This color can be changed if you don’t like the yellow **/
    border: 2px solid rgba(255,193,7,0.75);  
	/** Make the select line round **/
    border-radius:32px !important;
}

.dualbox-left-subpanel {
 top: 15rem; 
}
.dualbox-right-subpanel {
 top: 7rem; 
}

.dualbox-viewer {
  background-image:url("https://d16lzdky72u47i.cloudfront.net/shapex/6HpCqJZvFKb7WSZkq/drive/APPS/metahumans/Metahumans_Background.jpg");
    background-size: 100% 100%;
}
#menu-container {
    position: fixed;
    top: 50%;
    left: 0;
    transform: translateY(-50%);
    background-color: rgba(0, 0, 0, 0.5);
    border-radius: 30px 0 0 30px;
    padding: 10px;
    display: flex;
    flex-direction: column;
}

.menu-item {
    background-color: #ff6f00; /* Color de fondo de los elementos del menú */
    color: white;
    margin: 5px 0;
    padding: 10px 20px;
    border-radius: 20px 0 0 20px; /* Bordes redondeados por el lado izquierdo */
    font-weight: bold;
    cursor: pointer;
    transition: transform 0.3s ease-in-out, background-color 0.3s ease-in-out;
}

.menu-item:hover {
    transform: translateX(10px); /* Desplazar ligeramente a la derecha al pasar el ratón */
    background-color: #ff8f00; /* Cambiar el color de fondo al pasar el ratón */
}
